output.sparql:
PREFIX wd: <http://www.wikidata.org/entity/>
PREFIX wdt: <http://www.wikidata.org/prop/direct/>
SELECT DISTINCT ?start WHERE {
  wd:Q173782 wdt:P571 ?start .
}
ORDER BY ?start

args.sparql:
SELECT ?start ?end WHERE {
  wd:Q173782 wdt:P571 ?start.
  OPTIONAL { wd:Q173782 wdt:P582 ?end }
}

SELECT ?start ?end WHERE {
  wd:Q173782 p:P571/psn:P571 ?startNode.
  ?startNode rdf:type wikibase:TimeValue;
    wikibase:timePrecision ?precision.
  FILTER (?precision <= 9)
  BIND(xsd:dateTime(?startNode) AS ?dateTime)
  BIND(CONCAT(YEAR(?dateTime), '-01-01T00:00:00Z') AS ?start)
  OPTIONAL {
    wd:Q173782 p:P582/psn:P582 ?endNode.
    ?endNode rdf:type wikibase:TimeValue;
      wikibase:timePrecision ?endPrecision.
    FILTER (?endPrecision <= 9)
    BIND(xsd:dateTime(?endNode) AS ?endDateTime)
    BIND(CONCAT(YEAR(?endDateTime), '-01-01T00:00:00Z') AS ?end)
  }
}

SELECT ?start ?end WHERE {
  wd:Q173782 wdt:P571 ?start.
  OPTIONAL { wd:Q173782 wdt:P576 ?end }
}

SELECT DISTINCT ?start WHERE {
  wd:Q173782 wdt:P571 ?start.
}
ORDER BY ?start
